with codecs.open(file_path, "r", "utf-8") as f:
    content = f.read()

# Replace summary and plan using regex
content = re.sub(
    r'(7:\s*\{[\s\S]*?plan:\s*).*?(,\s*summary:).*?`[\s\S]*?`', 
    lambda m: f"{m.group(1)}{html_u7_plan}{m.group(2)} `{html_u7_summary}`", 
    content, 
    flags=re.DOTALL
)

with codecs.open(file_path, "w", "utf-8") as f:
    f.write(content)

